class MessageValidator:
    """Validates and sanitizes incoming Kafka messages securely."""

    ALLOWED_CURRENCIES = frozenset({"USD", "EUR", "GBP", "JPY", "CAD", "AUD", "CHF"})
    MAX_AMOUNT = Decimal("10000000.00")
    MIN_AMOUNT = Decimal("0.01")
    ACCOUNT_PATTERN = re.compile(r'^[A-Z0-9]{8,20}$')
    TRANSACTION_ID_PATTERN = re.compile(r'^[a-f0-9\-]{36}$')
    MAX_METADATA_KEYS = 10
    MAX_METADATA_VALUE_LENGTH = 256

    @classmethod
    def validate_transaction_id(cls, txn_id: str) -> bool:
        if not isinstance(txn_id, str):
            return False
        return bool(cls.TRANSACTION_ID_PATTERN.match(txn_id))

    @classmethod
    def validate_account(cls, account: str) -> bool:
        if not isinstance(account, str):
            return False
        return bool(cls.ACCOUNT_PATTERN.match(account))

    @classmethod
    def validate_amount(cls, amount_str: Any) -> Optional[Decimal]:
        try:
            amount = Decimal(str(amount_str))
            if amount < cls.MIN_AMOUNT or amount > cls.MAX_AMOUNT:
                return None
            if amount.as_tuple().exponent < -2:
                return None
            return amount
        except (InvalidOperation, ValueError, TypeError):
            return None

    @classmethod
    def validate_currency(cls, currency: str) -> bool:
        return isinstance(currency, str) and currency in cls.ALLOWED_CURRENCIES

    @classmethod
    def validate_transaction_type(cls, txn_type: str) -> Optional[TransactionType]:
        try:
            return TransactionType(txn_type)
        except ValueError:
            return None

    @classmethod
    def validate_metadata(cls, metadata: Any) -> Optional[Dict[str, str]]:
        if metadata is None:
            return {}
        if not isinstance(metadata, dict):
            return None
        if len(metadata) > cls.MAX_METADATA_KEYS:
            return None
        sanitized = {}
        for key, value in metadata.items():
            if not isinstance(key, str) or not isinstance(value, str):
                return None
            if len(key) > 64 or len(value) > cls.MAX_METADATA_VALUE_LENGTH:
                return None
            safe_key = re.sub(r'[^a-zA-Z0-9_\-]', '', key)
            safe_value = re.sub(r'[^\w\s\-.,@#]', '', value)
            if safe_key:
                sanitized[safe_key] = safe_value
        return sanitized

    @classmethod
    def validate_timestamp(cls, timestamp: str) -> bool:
        if not isinstance(timestamp, str):
            return False
        try:
            dt = datetime.fromisoformat(timestamp.replace('Z', '+00:00'))
            now = datetime.now(timezone.utc)
            diff = abs((now - dt).total_seconds())
            if diff > 86400:
                return False
            return True
        except (ValueError, TypeError):
            return False

    @classmethod
    def validate_and_parse(cls, raw_data: dict) -> Optional[Transaction]:
        required_fields = {"transaction_id", "transaction_type", "amount",
                           "currency", "source_account", "timestamp"}
        if not isinstance(raw_data, dict):
            logger.warning("Message is not a valid dictionary")
            return None

        if not required_fields.issubset(raw_data.keys()):
            missing = required_fields - raw_data.keys()
            logger.warning("Missing required fields: %s", missing)
            return None

        if not cls.validate_transaction_id(raw_data["transaction_id"]):
            logger.warning("Invalid transaction ID format")
            return None

        txn_type = cls.validate_transaction_type(raw_data["transaction_type"])
        if txn_type is None:
            logger.warning("Invalid transaction type")
            return None

        amount = cls.validate_amount(raw_data["amount"])
        if amount is None:
            logger.warning("Invalid amount")
            return None

        if not cls.validate_currency(raw_data["currency"]):
            logger.warning("Invalid currency")
            return None

        if not cls.validate_account(raw_data["source_account"]):
            logger.warning("Invalid source account format")
            return None

        dest_account = raw_data.get("destination_account")
        if dest_account is not None:
            if not cls.validate_account(dest_account):
                logger.warning("Invalid destination account format")
                return None

        if not cls.validate_timestamp(raw_data["timestamp"]):
            logger.warning("Invalid timestamp")
            return None

        metadata = cls.validate_metadata(raw_data.get("metadata"))
        if metadata is None:
            logger.warning("Invalid metadata")
            return None

        return Transaction(
            transaction_id=raw_data["transaction_id"],
            transaction_type=txn_type,
            amount=amount,
            currency=raw_data["currency"],
            source_account=raw_data["source_account"],
            destination_account=dest_account,
            timestamp=raw_data["timestamp"],
            metadata=metadata
        )


class MessageIntegrityVerifier:
    """Verifies message integrity using HMAC signatures."""

    def __init__(self):
        self._secret_key = os.environ.get("KAFKA_MESSAGE_HMAC_SECRET")
        if not self._secret_key:
            raise EnvironmentError(
                "KAFKA_MESSAGE_HMAC_SECRET environment variable must be set"
            )

    def verify_signature(self, payload: bytes, signature: str) -> bool:
        if not signature or not isinstance(signature, str):
            return False
        expected = hmac.new(
            self._secret_key.encode('utf-8'),
            payload,
            hashlib.sha256
        ).hexdigest()
        return hmac.compare_digest(expected, signature)


class TransactionHandlerRegistry:
    """
    Registry for transaction handlers using an explicit allowlist.
    Prevents dynamic/arbitrary code execution by only allowing
    pre-registered handler functions.
    """

    def __init__(self):
        self._handlers: Dict[TransactionType, Callable[[Transaction], TransactionStatus]] = {}

    def register(self, txn_type: TransactionType, handler: Callable[[Transaction], TransactionStatus]):
        if txn_type not in TransactionType:
            raise ValueError(f"Invalid transaction type: {txn_type}")
        self._handlers[txn_type] = handler
        logger.info("Registered handler for transaction type: %s", txn_type.value)

    def get_handler(self, txn_type: TransactionType) -> Optional[Callable[[Transaction], TransactionStatus]]:
        return self._handlers.get(txn_type)

    def has_handler(self, txn_type: TransactionType) -> bool:
        return txn_type in self._handlers


